import{_ as s,c as a,o as i,aN as t}from"./chunks/framework.CqA5BTDU.js";const k=JSON.parse('{"title":"Operator入门","description":"","frontmatter":{},"headers":[],"relativePath":"18.运维开发/Go语言/07-Operator入门.md","filePath":"18.运维开发/Go语言/07-Operator入门.md","lastUpdated":null}'),n={name:"18.运维开发/Go语言/07-Operator入门.md"};function p(l,e,o,r,d,c){return i(),a("div",null,[...e[0]||(e[0]=[t(`<h1 id="operator入门" tabindex="-1">Operator入门 <a class="header-anchor" href="#operator入门" aria-label="Permalink to &quot;Operator入门&quot;">​</a></h1><p>Operator 开发把 Kubernetes 控制器模式用到自定义资源上。CRD 定义新的资源类型，用户写 <code>spec</code> 描述期望状态，Controller 监听资源变化并执行 reconcile，把实际资源调整到接近期望状态，再把结果写回 <code>status</code>。</p><p>Kubernetes 章节里的 <a href="/kb/10.Kubernetes/22-CRD与控制器">CRD 与控制器</a> 和 <a href="/kb/10.Kubernetes/23-Operator运维">Operator 运维</a> 更偏集群运维视角；Go 语言里的 Operator 入门重点放在程序结构、controller-runtime、Reconcile、权限和本地运行。</p><p>普通 Kubernetes 资源已经有内置控制器维护，比如 Deployment Controller 会根据 Deployment 创建 ReplicaSet 和 Pod。Operator 做的是同一类事，只是资源类型换成了业务或平台自定义对象，比如 <code>BackupJob</code>、<code>Prometheus</code>、<code>Certificate</code>。自定义资源保存期望状态，自定义控制器负责把这些期望状态翻译成真实资源和外部动作。</p><h2 id="一、从脚本到控制器" tabindex="-1">一、从脚本到控制器 <a class="header-anchor" href="#一、从脚本到控制器" aria-label="Permalink to &quot;一、从脚本到控制器&quot;">​</a></h2><p>普通脚本通常是一次性执行：</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>读取参数 -&gt; 调用 API -&gt; 输出结果 -&gt; 进程退出</span></span></code></pre></div><p>控制器是持续运行的循环：</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>监听资源变化 -&gt; 读取期望状态 -&gt; 查询实际状态 -&gt; 修正差异 -&gt; 更新状态 -&gt; 等待下一次变化</span></span></code></pre></div><p>手工维护一个备份任务时，操作可能是创建 CronJob、挂载 Secret、设置保留时间、检查最近一次执行结果。Operator 会把这些动作收进控制器里，让集群里出现一个更贴近业务语义的资源，例如 <code>BackupJob</code>。</p><p>这里的 <code>BackupJob</code> 不是 Kubernetes 内置资源。它只是一个示例自定义资源，表示“某个目标需要按计划备份”。CRD 安装后，API Server 才认识这个 kind；Controller 运行后，这个 kind 才会产生实际动作。</p><div class="mermaid-diagram" data-mermaid-code="flowchart%20LR%0A%20%20%20%20cr%5B%22BackupJob%3Cbr%2F%3Espec%3A%20target%20%2F%20schedule%20%2F%20retention%22%5D%20--%3E%20controller%5B%22BackupJob%20Controller%3Cbr%2F%3EReconcile%22%5D%0A%20%20%20%20controller%20--%3E%20cronjob%5B%22CronJob%22%5D%0A%20%20%20%20controller%20--%3E%20secret%5B%22Secret%22%5D%0A%20%20%20%20controller%20--%3E%20status%5B%22BackupJob%3Cbr%2F%3Estatus%3A%20Ready%20%2F%20LastBackupTime%22%5D%0A"></div><p>CRD 只负责让 API Server 认识 <code>BackupJob</code> 这种对象。创建 CronJob、更新 status、处理删除清理，都由 Controller 完成。</p><p>CronJob 是 Kubernetes 内置的定时任务资源。BackupJob Controller 可以根据 <code>BackupJob.spec.schedule</code> 创建对应 CronJob，让 Kubernetes 自己按时间启动备份 Pod。这样自定义资源负责表达“我要备份什么、什么时候备份”，内置资源负责具体调度执行。</p><h2 id="二、operator-的程序组成" tabindex="-1">二、Operator 的程序组成 <a class="header-anchor" href="#二、operator-的程序组成" aria-label="Permalink to &quot;二、Operator 的程序组成&quot;">​</a></h2><p>一个基于 controller-runtime 的 Operator 通常包含这些对象：</p><table tabindex="0"><thead><tr><th>组成</th><th>作用</th></tr></thead><tbody><tr><td>API Type</td><td>Go 结构体，定义 <code>spec</code> 和 <code>status</code> 字段</td></tr><tr><td>CRD</td><td>由 API Type 生成，安装到集群后提供新资源类型</td></tr><tr><td>Manager</td><td>管理 RESTConfig、缓存、Client、Controller、Webhook、指标</td></tr><tr><td>Controller</td><td>监听资源变化，把事件交给 Reconcile</td></tr><tr><td>Reconciler</td><td>核心处理逻辑，对比期望状态和实际状态</td></tr><tr><td>Scheme</td><td>注册 Go 类型和 Kubernetes GroupVersionKind 的映射</td></tr><tr><td>RBAC</td><td>授权控制器读写相关资源</td></tr></tbody></table><p>API Type 和 CRD 是同一件事的两种形态。API Type 是 Go 代码里的结构体，开发时编辑它；CRD 是安装到集群里的 YAML，API Server 用它校验和保存对象。Kubebuilder 会根据 API Type 生成 CRD。</p><p><code>controller-runtime</code> 对 client-go 做了一层封装。它仍然使用 RESTConfig、Informer 和 Client，只是把缓存、事件监听、队列、重试、leader election 等常用能力整理成统一结构。</p><p>Manager 是 Operator 进程里的总入口。它启动缓存、注册 Controller、暴露指标、处理 leader election，并把同一份 RESTConfig 和 Scheme 分给各个控制器使用。单个 Operator 进程里可以同时管理多个 Controller。</p><h2 id="三、controller-runtime-里的-client" tabindex="-1">三、controller-runtime 里的 Client <a class="header-anchor" href="#三、controller-runtime-里的-client" aria-label="Permalink to &quot;三、controller-runtime 里的 Client&quot;">​</a></h2><p>controller-runtime 的 <code>client.Client</code> 和上一节的 ClientSet 不太一样。</p><table tabindex="0"><thead><tr><th>客户端</th><th>适合场景</th></tr></thead><tbody><tr><td><code>kubernetes.ClientSet</code></td><td>访问 Kubernetes 内置资源，调用路径类型化</td></tr><tr><td><code>dynamic.Interface</code></td><td>临时访问未知 GVR 的资源</td></tr><tr><td><code>controller-runtime client.Client</code></td><td>Operator 里同时访问内置资源和自定义资源</td></tr></tbody></table><p>controller-runtime client 通过 Scheme 识别资源类型。自定义资源的 Go 类型注册到 Scheme 后，代码里可以用同一个 client 读取 <code>BackupJob</code>，也可以读取 Deployment、Secret、CronJob。</p><p>Scheme 解决的是“Go 结构体和 Kubernetes 资源类型怎么对应”的问题。例如 <code>BackupJob{}</code> 这个 Go 类型要对应到 <code>ops.example.com/v1alpha1</code> 里的 <code>BackupJob</code> kind；<code>appsv1.Deployment{}</code> 要对应到 <code>apps/v1</code> 里的 Deployment。没有注册到 Scheme 的类型，client 不知道它应该请求哪个 API 路径。</p><p>默认情况下，读操作常从本地缓存读取，写操作直接发给 API Server。刚写完对象立刻从缓存读，可能短暂读到旧值。对强一致要求高的地方，需要理解 cache client 和 direct API reader 的差异。</p><h2 id="四、reconcile-模式" tabindex="-1">四、Reconcile 模式 <a class="header-anchor" href="#四、reconcile-模式" aria-label="Permalink to &quot;四、Reconcile 模式&quot;">​</a></h2><p>Reconcile 的输入通常只有一个 <code>namespace/name</code>，也就是发生变化的对象键。控制器拿到 key 后重新读取当前对象，再根据最新状态处理。</p><p>典型流程：</p><table tabindex="0"><thead><tr><th>步骤</th><th>内容</th></tr></thead><tbody><tr><td>读取自定义资源</td><td>根据 <code>namespace/name</code> 获取 <code>BackupJob</code></td></tr><tr><td>处理已删除对象</td><td>对象不存在时结束；带 finalizer 时执行外部清理</td></tr><tr><td>读取关联资源</td><td>查看 CronJob、Secret、ConfigMap 是否存在</td></tr><tr><td>创建或更新资源</td><td>实际状态不符合 <code>spec</code> 时进行调整</td></tr><tr><td>更新 status</td><td>写入 Ready、原因、最后执行时间等状态</td></tr><tr><td>返回结果</td><td>成功结束、延迟重试或按错误重试</td></tr></tbody></table><p>Reconcile 不是“事件来了就按事件内容改一下”。更稳的写法是每次都读取当前完整状态，然后计算实际状态和期望状态的差异。新增、更新、重试、进程重启后重新同步，都走同一套逻辑。</p><p>这种写法要求 Reconcile 幂等。幂等的意思是同一个对象被处理多次，结果仍然稳定。例如 CronJob 已经存在且字段正确时，Reconcile 再跑一次应该什么也不改；CronJob 不存在时才创建；字段不一致时才更新。控制器重启、watch 重连、事件重复投递都会让同一个对象被多次处理。</p><p>Reconcile 返回错误时，controller-runtime 会把这个 key 重新放回队列，后续再试。返回 <code>RequeueAfter</code> 时，即使没有新事件，也会在指定时间后再处理一次，适合定期检查外部状态。</p><h2 id="五、spec-和-status" tabindex="-1">五、spec 和 status <a class="header-anchor" href="#五、spec-和-status" aria-label="Permalink to &quot;五、spec 和 status&quot;">​</a></h2><p>自定义资源一般分成 <code>spec</code> 和 <code>status</code>：</p><div class="language-yaml vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">yaml</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#22863A;--shiki-dark:#85E89D;">apiVersion</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">ops.example.com/v1alpha1</span></span>
<span class="line"><span style="--shiki-light:#22863A;--shiki-dark:#85E89D;">kind</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">BackupJob</span></span>
<span class="line"><span style="--shiki-light:#22863A;--shiki-dark:#85E89D;">metadata</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">:</span></span>
<span class="line"><span style="--shiki-light:#22863A;--shiki-dark:#85E89D;">  name</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">mysql-daily</span></span>
<span class="line"><span style="--shiki-light:#22863A;--shiki-dark:#85E89D;">  namespace</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">ops</span></span>
<span class="line"><span style="--shiki-light:#22863A;--shiki-dark:#85E89D;">spec</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">:</span></span>
<span class="line"><span style="--shiki-light:#22863A;--shiki-dark:#85E89D;">  target</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">mysql</span></span>
<span class="line"><span style="--shiki-light:#22863A;--shiki-dark:#85E89D;">  schedule</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;10 2 * * *&quot;</span></span>
<span class="line"><span style="--shiki-light:#22863A;--shiki-dark:#85E89D;">  retentionDays</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">7</span></span>
<span class="line"><span style="--shiki-light:#22863A;--shiki-dark:#85E89D;">status</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">:</span></span>
<span class="line"><span style="--shiki-light:#22863A;--shiki-dark:#85E89D;">  ready</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">true</span></span>
<span class="line"><span style="--shiki-light:#22863A;--shiki-dark:#85E89D;">  lastBackupTime</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;2026-05-29T02:10:00Z&quot;</span></span>
<span class="line"><span style="--shiki-light:#22863A;--shiki-dark:#85E89D;">  message</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;last backup succeeded&quot;</span></span></code></pre></div><p><code>spec</code> 是期望状态，通常由用户、GitOps 或平台写入。<code>status</code> 是实际状态，通常由 Controller 写入。排查 Operator 时，<code>status.conditions</code>、<code>message</code>、<code>observedGeneration</code> 这些字段能说明控制器处理到了哪个版本、失败原因是什么。</p><p><code>conditions</code> 通常是一组状态项，比如 <code>Ready=True</code>、<code>BackupSucceeded=False</code>。每个 condition 里会带 <code>type</code>、<code>status</code>、<code>reason</code>、<code>message</code>、<code>lastTransitionTime</code>。用户看到自定义资源没有生效时，先看 status 比直接翻 controller 日志更快。</p><p><code>observedGeneration</code> 常用于判断 status 是否对应最新 spec。用户改了 spec 后，<code>metadata.generation</code> 会增加；控制器处理完成后，把 <code>status.observedGeneration</code> 更新成同一个值。两者不一致时，说明 status 可能还是旧状态。</p><h2 id="六、ownerreference-和-finalizer" tabindex="-1">六、OwnerReference 和 finalizer <a class="header-anchor" href="#六、ownerreference-和-finalizer" aria-label="Permalink to &quot;六、OwnerReference 和 finalizer&quot;">​</a></h2><p>Operator 创建子资源时，通常给子资源加 OwnerReference。这样可以表达“这个 CronJob 属于这个 BackupJob”。</p><p>OwnerReference 的作用：</p><table tabindex="0"><thead><tr><th>作用</th><th>说明</th></tr></thead><tbody><tr><td>资源关系</td><td><code>kubectl describe</code> 时能看出父子关系</td></tr><tr><td>事件回溯</td><td>子资源变化可以触发父资源 Reconcile</td></tr><tr><td>垃圾回收</td><td>父资源删除后，Kubernetes 可以清理子资源</td></tr></tbody></table><p>finalizer 用于删除前清理外部资源。比如 Operator 在云厂商创建了一个对象存储 bucket，删除 CR 时需要先删除或解绑外部 bucket，再移除 finalizer。控制器异常时，带 finalizer 的资源可能卡在 <code>Terminating</code>。</p><div class="language-yaml vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">yaml</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#22863A;--shiki-dark:#85E89D;">metadata</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">:</span></span>
<span class="line"><span style="--shiki-light:#22863A;--shiki-dark:#85E89D;">  finalizers</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">:</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    - </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">backup.ops.example.com/finalizer</span></span></code></pre></div><p>finalizer 处理要保持幂等。清理动作执行一半失败后，下一次 Reconcile 会再次进入删除流程；重复删除已经不存在的外部资源，应该返回成功或可识别的结果。</p><p>OwnerReference 处理的是 Kubernetes 内部资源之间的归属关系，finalizer 处理的是删除前还需要额外做的清理动作。只创建 CronJob 这类子资源时，OwnerReference 往往够用；还创建了云资源、DNS 记录、外部账号这类 Kubernetes 不知道的对象时，通常需要 finalizer。</p><h2 id="七、用-kubebuilder-生成骨架" tabindex="-1">七、用 Kubebuilder 生成骨架 <a class="header-anchor" href="#七、用-kubebuilder-生成骨架" aria-label="Permalink to &quot;七、用 Kubebuilder 生成骨架&quot;">​</a></h2><p>Kubebuilder 是 controller-runtime 生态里常用的脚手架工具。它生成项目结构、API 类型、Controller、RBAC 标记、Makefile 和部署清单。</p><p>常见初始化命令：</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">kubebuilder</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> init</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> \\</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">  --domain</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> example.com</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> \\</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">  --repo</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> example.com/backup-operator</span></span>
<span class="line"></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">kubebuilder</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> create</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> api</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> \\</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">  --group</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> ops</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> \\</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">  --version</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> v1alpha1</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> \\</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">  --kind</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> BackupJob</span></span></code></pre></div><p>生成后的目录大致是：</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>backup-operator/</span></span>
<span class="line"><span>├── api/</span></span>
<span class="line"><span>│   └── v1alpha1/</span></span>
<span class="line"><span>│       ├── backupjob_types.go</span></span>
<span class="line"><span>│       └── groupversion_info.go</span></span>
<span class="line"><span>├── internal/</span></span>
<span class="line"><span>│   └── controller/</span></span>
<span class="line"><span>│       └── backupjob_controller.go</span></span>
<span class="line"><span>├── config/</span></span>
<span class="line"><span>│   ├── crd/</span></span>
<span class="line"><span>│   ├── rbac/</span></span>
<span class="line"><span>│   ├── manager/</span></span>
<span class="line"><span>│   └── samples/</span></span>
<span class="line"><span>├── cmd/</span></span>
<span class="line"><span>│   └── main.go</span></span>
<span class="line"><span>├── go.mod</span></span>
<span class="line"><span>└── Makefile</span></span></code></pre></div><p><code>api/</code> 里写资源字段，<code>internal/controller/</code> 里写 Reconcile，<code>config/</code> 里放生成出来的 CRD、RBAC 和部署清单。小型 Operator 的核心改动通常集中在 API Type 和 Reconciler 两处。</p><p><code>config/samples/</code> 里的 YAML 是一个示例自定义资源，用来验证 CRD 和 Controller 是否工作。它不是 CRD 本身，而是 CRD 安装后创建出来的一条 <code>BackupJob</code> 实例。</p><h2 id="八、本地运行链路" tabindex="-1">八、本地运行链路 <a class="header-anchor" href="#八、本地运行链路" aria-label="Permalink to &quot;八、本地运行链路&quot;">​</a></h2><p>本地开发 Operator 时，常见流程是先把 CRD 安装进集群，再在本机运行控制器进程。</p><p>当前状态：集群里还没有 <code>BackupJob</code> 这种资源。</p><p>安装 CRD：</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">make</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> install</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">kubectl</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> get</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> crd</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> |</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;"> grep</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> backupjobs</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">kubectl</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> api-resources</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> |</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;"> grep</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> BackupJob</span></span></code></pre></div><p><code>make install</code> 通常只安装 CRD，不会启动控制器。执行后，集群里能创建 <code>BackupJob</code> 对象，但如果控制器没运行，它不会自动创建 CronJob，也不会更新 status。</p><p>启动控制器：</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">make</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> run</span></span></code></pre></div><p>另一个终端创建示例资源：</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">kubectl</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> apply</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -f</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> config/samples/ops_v1alpha1_backupjob.yaml</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">kubectl</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> get</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> backupjob</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -A</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">kubectl</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> describe</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> backupjob</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> mysql-daily</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -n</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> ops</span></span></code></pre></div><p>创建示例资源后，API Server 会保存这条 <code>BackupJob</code>。正在运行的控制器通过缓存和队列收到变化，再进入 Reconcile。Reconcile 里如果创建了 CronJob，可以继续用 <code>kubectl get cronjob -n ops</code> 验证子资源是否出现。</p><p>控制器进程会使用当前 kubeconfig 连接集群。本地 <code>kubectl</code> 指向哪个 context，<code>make run</code> 通常也会指向同一个集群。多集群环境下，运行前先确认 <code>kubectl config current-context</code>。</p><h2 id="九、部署到集群" tabindex="-1">九、部署到集群 <a class="header-anchor" href="#九、部署到集群" aria-label="Permalink to &quot;九、部署到集群&quot;">​</a></h2><p>本地运行验证通过后，控制器通常会被打成镜像，作为 Deployment 跑在集群里。部署清单会包含 ServiceAccount、RBAC、Deployment、LeaderElection 相关权限和指标端口。</p><p>常见命令：</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">make</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> docker-build</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> docker-push</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> IMG=registry.example.com/ops/backup-operator:v0.1.0</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">make</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> deploy</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> IMG=registry.example.com/ops/backup-operator:v0.1.0</span></span></code></pre></div><p><code>make docker-build</code> 构建控制器镜像，<code>make docker-push</code> 推送到镜像仓库，<code>make deploy</code> 把 Deployment、ServiceAccount、RBAC 等资源安装到集群里。<code>IMG</code> 指定集群里最终要拉取的控制器镜像地址。</p><p>部署后检查：</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">kubectl</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> get</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> deploy,pod</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -n</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> backup-operator-system</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">kubectl</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> logs</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> deploy/backup-operator-controller-manager</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -n</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> backup-operator-system</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">kubectl</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> auth</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> can-i</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> list</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> backupjobs.ops.example.com</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> \\</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">  --as=system:serviceaccount:backup-operator-system:backup-operator-controller-manager</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> \\</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">  -A</span></span></code></pre></div><p>Operator 在集群里运行时不再读取本机 kubeconfig，而是使用 Pod 的 ServiceAccount。权限问题通常表现为 controller 日志里出现 <code>forbidden</code>，用户侧现象是 CR 创建成功，但子资源没有创建或 status 不更新。</p><h2 id="十、常见错误" tabindex="-1">十、常见错误 <a class="header-anchor" href="#十、常见错误" aria-label="Permalink to &quot;十、常见错误&quot;">​</a></h2><table tabindex="0"><thead><tr><th>现象</th><th>用户侧表现</th><th>常见原因</th><th>排查入口</th></tr></thead><tbody><tr><td><code>no matches for kind</code></td><td>apply 示例 CR 时直接报错，API Server 不认识这个 kind</td><td>CRD 没安装或 apiVersion 写错</td><td><code>kubectl get crd</code>、<code>kubectl api-resources</code></td></tr><tr><td>CR 创建成功但没有子资源</td><td><code>kubectl get backupjob</code> 能看到对象，但没有 CronJob/Secret</td><td>Controller 没运行、RBAC 不足、Reconcile 没匹配到对象</td><td>controller 日志、事件、<code>kubectl auth can-i</code></td></tr><tr><td>status 不更新</td><td><code>kubectl get -o yaml</code> 里 status 为空或 observedGeneration 落后</td><td>status 子资源未启用、权限缺少 <code>/status</code>、更新冲突</td><td>CRD、RBAC、controller 日志</td></tr><tr><td>删除卡住 Terminating</td><td><code>kubectl delete</code> 后对象一直存在，metadata 有 deletionTimestamp</td><td>finalizer 清理失败</td><td><code>metadata.finalizers</code>、controller 日志、外部资源状态</td></tr><tr><td>控制器反复更新同一对象</td><td>Events 或日志里持续出现 update，同一资源频繁变更</td><td>Reconcile 不幂等、默认值和期望值反复漂移</td><td>对比对象 YAML、查看 managedFields 和日志</td></tr><tr><td>本地运行连错集群</td><td>示例 CR 出现在另一个集群，当前集群没有变化</td><td>kubeconfig context 不对</td><td><code>kubectl config current-context</code></td></tr></tbody></table><p>Operator 的排查入口通常不是业务 Pod 的日志，而是 Controller 日志、CR 的 status、Events、RBAC 和子资源的 OwnerReference。控制器把“为什么要创建或修改这些对象”的原因保存在这些地方。</p><h2 id="十一、和-client-go-的关系" tabindex="-1">十一、和 client-go 的关系 <a class="header-anchor" href="#十一、和-client-go-的关系" aria-label="Permalink to &quot;十一、和 client-go 的关系&quot;">​</a></h2><p>Operator 看起来比 client-go 多了很多目录和生成文件，但底层链路仍然相同：</p><div class="mermaid-diagram" data-mermaid-code="flowchart%20LR%0A%20%20%20%20kubeconfig%5B%22%E6%9C%AC%E5%9C%B0%20kubeconfig%3Cbr%2F%3E%E6%88%96%20Pod%20ServiceAccount%22%5D%20--%3E%20restconfig%5B%22RESTConfig%22%5D%0A%20%20%20%20restconfig%20--%3E%20manager%5B%22controller-runtime%20Manager%22%5D%0A%20%20%20%20manager%20--%3E%20cache%5B%22Informer%20Cache%22%5D%0A%20%20%20%20manager%20--%3E%20client%5B%22controller-runtime%20Client%22%5D%0A%20%20%20%20cache%20--%3E%20reconcile%5B%22Reconcile%22%5D%0A%20%20%20%20client%20--%3E%20apiserver%5B%22API%20Server%22%5D%0A"></div><p>client-go 提供访问 Kubernetes API 的底层能力；controller-runtime 把这些能力组织成适合写控制器的框架。理解 kubeconfig、RESTConfig、ClientSet、Informer 后，再看 Operator 的 Manager、Cache、Client、Reconcile，会少很多凭空出现的概念。</p>`,82)])])}const u=s(n,[["render",p]]);export{k as __pageData,u as default};
